`,paraId:11,tocIndex:4},{value:"4\u3001\u4F7F\u7528 postMessage \u65B9\u6CD5\uFF0C\u5982\u679C\u6211\u4EEC\u80FD\u591F\u83B7\u5F97\u5BF9\u5E94\u6807\u7B7E\u9875\u7684\u5F15\u7528\uFF0C\u5C31\u53EF\u4EE5\u4F7F\u7528 postMessage \u65B9\u6CD5\uFF0C\u8FDB\u884C\u901A\u4FE1\u3002",paraId:12,tocIndex:4},{value:"postMessage \u662F\u4E00\u79CD\u5B89\u5168\u5730\u5B9E\u73B0\u8DE8\u6E90\u901A\u4FE1\u7684\u65B9\u6CD5\u3002\u5728\u6D4F\u89C8\u5668\u4E2D\uFF0C\u4E0D\u540C\u7684\u7A97\u53E3\u3001iframe\u3001worker \u7B49\u53EF\u4EE5\u5229\u7528 postMessage \u65B9\u6CD5\u6765\u76F8\u4E92\u53D1\u9001\u6D88\u606F\uFF0C\u5373\u4F7F\u5B83\u4EEC\u6765\u81EA\u4E0D\u540C\u7684\u57DF\uFF08\u4E5F\u5C31\u662F\u8DE8\u57DF\uFF09\u3002\u8FD9\u4F7F\u5F97\u5728\u4F8B\u5982\u7236\u7A97\u53E3\u548C\u5B50 iframe \u4E4B\u95F4\u6216\u8005\u4E3B\u7EBF\u7A0B\u548C Web Worker \u4E4B\u95F4\u7684\u6570\u636E\u4EA4\u6362\u6210\u4E3A\u53EF\u80FD\u3002",paraId:13,tocIndex:4},{value:"\u4EE5\u4E0B\u662F postMessage \u4F7F\u7528\u7684\u57FA\u7840\u6B65\u9AA4\uFF1A",paraId:14,tocIndex:4},{value:`// \u53D1\u9001\u6D88\u606F
windowA.postMessage(message, targetOrigin);
// \u63A5\u6536\u6D88\u606F
window.addEventListener('message', (event) => {
  // Do something with event.data
  console.log('Received message:', event.data);

  // \u53EF\u4EE5\u68C0\u67E5event.origin\u6765\u9A8C\u8BC1\u6D88\u606F\u53D1\u9001\u8005\u7684\u6E90
  if (event.origin === 'https://trusted-source.com') {
    // \u5982\u679C\u6E90\u662F\u53EF\u4FE1\u7684\uFF0C\u5904\u7406\u6D88\u606F
    processMessage(event.data);
  } else {
    // \u5982\u679C\u6E90\u4E0D\u662F\u9884\u671F\u7684\uFF0C\u5219\u5FFD\u7565\u6D88\u606F
    console.warn('Untrusted message source:', event.origin);
  }
});
